package persona

// Persona represents an AI personality definition
type Persona struct {
	// Name is the unique identifier for the persona
	Name string `yaml:"name"`

	// Roles is the list of roles this persona can fulfill
	Roles []string `yaml:"roles"`

	// Description is a brief description of the persona's approach
	Description string `yaml:"description"`

	// Tags are keywords for discovery and categorization
	Tags []string `yaml:"tags"`

	// Content is the markdown content (body) of the persona
	Content string `yaml:"-"` // Not included in YAML frontmatter

	// Source identifies where the persona came from: "library" or "project".
	// Library personas are read-only; project personas are editable.
	Source string `yaml:"-"`

	// FilePath is the absolute path on disk where the persona lives.
	FilePath string `yaml:"-"`
}

// Source constants identify where a persona came from.
const (
	SourceLibrary = "library"
	SourceProject = "project"
)

// PersonaLoader interface for loading and discovering personas
type PersonaLoader interface {
	// LoadPersona loads a persona by name from the file system
	LoadPersona(name string) (*Persona, error)

	// ListPersonas returns all available personas
	ListPersonas() ([]*Persona, error)

	// FindByRole returns personas that can fulfill the specified role
	FindByRole(role string) ([]*Persona, error)

	// FindByTags returns personas that have all the specified tags
	FindByTags(tags []string) ([]*Persona, error)
}

// BindingManager interface for managing persona-role bindings
type BindingManager interface {
	// GetBinding returns the persona bound to the specified role
	GetBinding(role string) (string, error)

	// SetBinding binds a persona to a role
	SetBinding(role, persona string) error

	// GetAllBindings returns all current role-persona bindings
	GetAllBindings() (map[string]string, error)

	// RemoveBinding removes the binding for the specified role
	RemoveBinding(role string) error

	// GetOverride returns the persona override for a specific workflow and role
	GetOverride(workflow, role string) (string, error)
}

// ClaudeInjector interface for managing personas in CLAUDE.md
type ClaudeInjector interface {
	// InjectPersona injects a single persona into CLAUDE.md for the specified role
	InjectPersona(persona *Persona, role string) error

	// InjectMultiple injects multiple personas into CLAUDE.md
	// The map key is the role, value is the persona
	InjectMultiple(personas map[string]*Persona) error

	// RemovePersonas removes all personas from CLAUDE.md
	RemovePersonas() error

	// GetLoadedPersonas returns the currently loaded personas as role->persona map
	GetLoadedPersonas() (map[string]string, error)
}

// PersonaBinding represents a role-persona binding
type PersonaBinding struct {
	Role    string `yaml:"role"`
	Persona string `yaml:"persona"`
}

// PersonaConfig represents the persona configuration in .ddx.yml
type PersonaConfig struct {
	// Bindings maps roles to persona names
	Bindings map[string]string `yaml:"persona_bindings,omitempty"`

	// Overrides provides workflow-specific persona overrides
	// First key is workflow name, second key is role, value is persona name
	Overrides map[string]map[string]string `yaml:"overrides,omitempty"`
}

// PersonaError represents persona-specific errors
type PersonaError struct {
	Type    string
	Message string
	Cause   error
}

func (e *PersonaError) Error() string {
	if e.Cause != nil {
		return e.Message + ": " + e.Cause.Error()
	}
	return e.Message
}

func (e *PersonaError) Unwrap() error {
	return e.Cause
}

// Error types for persona operations
const (
	ErrorPersonaNotFound  = "persona_not_found"
	ErrorInvalidPersona   = "invalid_persona"
	ErrorBindingNotFound  = "binding_not_found"
	ErrorConfigNotFound   = "config_not_found"
	ErrorInvalidConfig    = "invalid_config"
	ErrorFileOperation    = "file_operation"
	ErrorValidation       = "validation"
	ErrorAlreadyExists    = "persona_already_exists"
	ErrorReadOnlyLibrary  = "persona_is_library_read_only"
	ErrorNoProjectContext = "no_project_context"
)

// NewPersonaError creates a new persona error
func NewPersonaError(errorType, message string, cause error) *PersonaError {
	return &PersonaError{
		Type:    errorType,
		Message: message,
		Cause:   cause,
	}
}

// PersonaMetadata holds metadata for persona discovery
type PersonaMetadata struct {
	Name        string   `json:"name"`
	Roles       []string `json:"roles"`
	Description string   `json:"description"`
	Tags        []string `json:"tags"`
	FilePath    string   `json:"file_path"`
	ModTime     string   `json:"mod_time"`
}

// LoadedPersonaInfo represents information about a loaded persona
type LoadedPersonaInfo struct {
	Name     string `json:"name"`
	Role     string `json:"role"`
	LoadTime string `json:"load_time"`
}

// PersonaUsageStats tracks persona usage statistics
type PersonaUsageStats struct {
	Name     string   `json:"name"`
	UseCount int      `json:"use_count"`
	LastUsed string   `json:"last_used"`
	Roles    []string `json:"roles"`
}

// Constants for persona file operations
const (
	// PersonasDir is the default directory for personas
	PersonasDir = ".ddx/personas"

	// PersonaFileExtension is the expected file extension for personas
	PersonaFileExtension = ".md"

	// ClaudeFileName is the name of the Claude configuration file
	ClaudeFileName = "CLAUDE.md"

	// ConfigFileName is the name of the DDx configuration file
	ConfigFileName = ".ddx.yml"

	// PersonasStartMarker marks the beginning of personas section in CLAUDE.md
	PersonasStartMarker = "<!-- PERSONAS:START -->"

	// PersonasEndMarker marks the end of personas section in CLAUDE.md
	PersonasEndMarker = "<!-- PERSONAS:END -->"

	// PersonasHeader is the header for the personas section
	PersonasHeader = "## Active Personas"

	// PersonasFooter is the footer instruction for the personas section
	PersonasFooter = "When responding, adopt the appropriate persona based on the task."
)

// Validation constants
const (
	// MaxPersonaFileSize is the maximum allowed size for a persona file (1MB)
	MaxPersonaFileSize = 1024 * 1024

	// MaxPersonasInClaude is the maximum number of personas that can be loaded
	MaxPersonasInClaude = 10

	// MaxRolesPerPersona is the maximum number of roles a persona can have
	MaxRolesPerPersona = 5

	// MaxTagsPerPersona is the maximum number of tags a persona can have
	MaxTagsPerPersona = 10
)

// DefaultPersonaTemplate provides a template for creating new personas
const DefaultPersonaTemplate = `---
name: {{name}}
roles: [{{role}}]
description: {{description}}
tags: [{{tags}}]
---

# {{title}}

You are {{description}}.

## Key Principles
-
-
-

## Approach
-
-
-

## Areas of Focus
-
-
-
`

// ExamplePersonas provides examples for documentation and testing
var ExamplePersonas = map[string]string{
	"code-reviewer": `---
name: code-reviewer
roles: [code-reviewer, security-analyst]
description: Uncompromising code quality enforcer
tags: [strict, security, production, quality]
---

# Code Reviewer

You are an experienced senior code reviewer who enforces high quality standards.
Your reviews are thorough, security-focused, and aimed at maintaining production quality.

## Review Principles
- Security vulnerabilities are non-negotiable
- Performance implications must be considered
- Code readability and maintainability are essential
- Test coverage requirements must be met

## Areas of Focus
- Security vulnerabilities and attack vectors
- Performance bottlenecks and optimizations
- Code complexity and maintainability
- Test coverage and quality
- Documentation completeness`,
package persona

import (
	"bufio"
	"bytes"
	"fmt"
	"os"
	"path/filepath"
	"strings"

	"github.com/DocumentDrivenDX/ddx/internal/config"
	"gopkg.in/yaml.v3"
)

// PersonaLoaderImpl implements the PersonaLoader interface.
//
// A loader can own up to two source directories:
//   - libraryDir: read-only, shared across projects.
//   - projectDir: project-local (`.ddx/personas`). When a project persona has
//     the same name as a library persona, the project persona wins for that
//     project's bindings.
type PersonaLoaderImpl struct {
	// libraryDir is the legacy single directory and remains in use when the
	// loader is constructed via NewPersonaLoaderWithDir for test fixtures.
	personasDir string
	projectDir  string
}

// NewPersonaLoader creates a new persona loader rooted at the project's
// working directory. It discovers the library path from config and the
// project-local `.ddx/personas` directory.
func NewPersonaLoader(workingDir string) PersonaLoader {
	libraryDir := resolveLibraryPersonasDir(workingDir)
	projectDir := resolveProjectPersonasDir(workingDir)
	return &PersonaLoaderImpl{
		personasDir: libraryDir,
		projectDir:  projectDir,
	}
}

// NewPersonaLoaderWithDir creates a new persona loader with a specific
// library directory. Kept for tests and back-compat callers that only need
// the library source.
func NewPersonaLoaderWithDir(dir string) PersonaLoader {
	return &PersonaLoaderImpl{
		personasDir: dir,
	}
}

// NewPersonaLoaderWithDirs creates a loader with explicit library and project
// directories. Either may be empty to disable that source.
func NewPersonaLoaderWithDirs(libraryDir, projectDir string) PersonaLoader {
	return &PersonaLoaderImpl{
		personasDir: libraryDir,
		projectDir:  projectDir,
	}
}

// resolveLibraryPersonasDir resolves the library persona directory.
func resolveLibraryPersonasDir(workingDir string) string {
	cfg, err := config.LoadWithWorkingDir(workingDir)
	if err != nil || cfg.Library == nil || cfg.Library.Path == "" {
		homeDir, _ := os.UserHomeDir()
		return filepath.Join(homeDir, ".ddx", "plugins", "ddx", "personas")
	}
	libPath := cfg.Library.Path
	if !filepath.IsAbs(libPath) && workingDir != "" {
		libPath = filepath.Join(workingDir, libPath)
	}
	return filepath.Join(libPath, "personas")
}

// resolveProjectPersonasDir returns the project-local persona directory.
func resolveProjectPersonasDir(workingDir string) string {
	if workingDir == "" {
		return ""
	}
	return filepath.Join(workingDir, ".ddx", "personas")
}

// LoadPersona loads a persona by name. Project-local personas override
// library personas with the same name.
func (l *PersonaLoaderImpl) LoadPersona(name string) (*Persona, error) {
	if name == "" {
		return nil, NewPersonaError(ErrorValidation, "persona name cannot be empty", nil)
	}

	if l.projectDir != "" {
		candidate := filepath.Join(l.projectDir, name+PersonaFileExtension)
		if fileExists(candidate) {
			return readPersonaFile(candidate, SourceProject)
		}
	}

	if l.personasDir != "" {
		candidate := filepath.Join(l.personasDir, name+PersonaFileExtension)
		if fileExists(candidate) {
			return readPersonaFile(candidate, SourceLibrary)
		}
	}

	return nil, NewPersonaError(ErrorPersonaNotFound,
		fmt.Sprintf("persona '%s' not found", name), nil)
}

// readPersonaFile reads a single persona file and tags it with its source.
func readPersonaFile(filePath, source string) (*Persona, error) {
	content, err := os.ReadFile(filePath)
	if err != nil {
		return nil, NewPersonaError(ErrorFileOperation,
			fmt.Sprintf("failed to read persona file %s", filePath), err)
	}
	if len(content) > MaxPersonaFileSize {
		return nil, NewPersonaError(ErrorValidation,
			fmt.Sprintf("persona file %s exceeds maximum size of %d bytes", filePath, MaxPersonaFileSize), nil)
	}
	persona, err := parsePersona(content)
	if err != nil {
		return nil, NewPersonaError(ErrorInvalidPersona,
			fmt.Sprintf("failed to parse persona %s", filePath), err)
	}
	persona.Source = source
	persona.FilePath = filePath
	return persona, nil
}

// ListPersonas returns all available personas. Project personas override
// library personas of the same name; both sets are listed, with the project
// persona taking precedence when names collide.
func (l *PersonaLoaderImpl) ListPersonas() ([]*Persona, error) {
	// Project personas first so they win on collision.
	byName := map[string]*Persona{}
	var ordered []string

	for _, dir := range []struct {
		path   string
		source string
	}{
		{l.projectDir, SourceProject},
		{l.personasDir, SourceLibrary},
	} {
		if dir.path == "" || !dirExists(dir.path) {
			continue
		}
		entries, err := os.ReadDir(dir.path)
		if err != nil {
			return nil, NewPersonaError(ErrorFileOperation,
				fmt.Sprintf("failed to read personas directory %s", dir.path), err)
		}
		for _, entry := range entries {
			if entry.IsDir() {
				continue
			}
			if !strings.HasSuffix(entry.Name(), PersonaFileExtension) {
				continue
			}
			if entry.Name() == "README.md" || entry.Name() == "readme.md" {
				continue
			}
			personaName := strings.TrimSuffix(entry.Name(), PersonaFileExtension)
			if _, seen := byName[personaName]; seen {
				continue
			}
			persona, err := readPersonaFile(filepath.Join(dir.path, entry.Name()), dir.source)
			if err != nil {
				_, _ = fmt.Fprintf(os.Stderr, "Warning: Skipping invalid persona %s: %v\n", entry.Name(), err)
				continue
			}
			byName[personaName] = persona
			ordered = append(ordered, personaName)
		}
	}

	result := make([]*Persona, 0, len(byName))
	for _, name := range ordered {
		result = append(result, byName[name])
	}
	return result, nil
}

// FindByRole returns personas that can fulfill the specified role.
func (l *PersonaLoaderImpl) FindByRole(role string) ([]*Persona, error) {
	if role == "" {
		return nil, NewPersonaError(ErrorValidation, "role cannot be empty", nil)
	}

	allPersonas, err := l.ListPersonas()
	if err != nil {
		return nil, err
	}

	var matchingPersonas []*Persona

	for _, persona := range allPersonas {
		for _, personaRole := range persona.Roles {
			if personaRole == role {
				matchingPersonas = append(matchingPersonas, persona)
				break
			}
		}
	}

	return matchingPersonas, nil
}

// FindByTags returns personas that have all the specified tags.
func (l *PersonaLoaderImpl) FindByTags(tags []string) ([]*Persona, error) {
	if len(tags) == 0 {
		return nil, NewPersonaError(ErrorValidation, "at least one tag must be specified", nil)
	}

	allPersonas, err := l.ListPersonas()
	if err != nil {
		return nil, err
	}

	var matchingPersonas []*Persona

	for _, persona := range allPersonas {
		if hasAllTags(persona.Tags, tags) {
			matchingPersonas = append(matchingPersonas, persona)
		}
	}

	return matchingPersonas, nil
}

// parsePersona parses a persona from markdown content with YAML frontmatter.
func parsePersona(content []byte) (*Persona, error) {
	frontmatter, markdownContent, err := splitFrontmatter(content)
	if err != nil {
		return nil, err
	}

	var persona Persona
	if err := yaml.Unmarshal(frontmatter, &persona); err != nil {
		return nil, NewPersonaError(ErrorInvalidPersona, "failed to parse YAML frontmatter", err)
	}

	persona.Content = string(markdownContent)

	if err := validatePersona(&persona); err != nil {
		return nil, err
	}

	return &persona, nil
}

// splitFrontmatter splits YAML frontmatter from markdown content.
func splitFrontmatter(content []byte) (frontmatter []byte, markdown []byte, err error) {
	scanner := bufio.NewScanner(bytes.NewReader(content))

	var lines []string
	for scanner.Scan() {
		lines = append(lines, scanner.Text())
	}

	if len(lines) < 2 {
		return nil, nil, NewPersonaError(ErrorInvalidPersona, "file too short to contain frontmatter", nil)
	}
package persona

import (
	"fmt"
	"os"
	"path/filepath"
	"strings"

	"gopkg.in/yaml.v3"
)

// ProjectPersonaWriter owns create/update/delete operations for project-local
// personas (files under `.ddx/personas/*.md`). Library personas are never
// mutated by this type; attempting to do so returns an ErrorReadOnlyLibrary.
type ProjectPersonaWriter struct {
	workingDir string
	loader     *PersonaLoaderImpl
}

// NewProjectPersonaWriter returns a writer rooted at the given working
// directory. Passing an empty working dir returns a writer that errors on
// all calls because there is no project context.
func NewProjectPersonaWriter(workingDir string) *ProjectPersonaWriter {
	loader := &PersonaLoaderImpl{
		personasDir: resolveLibraryPersonasDir(workingDir),
		projectDir:  resolveProjectPersonasDir(workingDir),
	}
	return &ProjectPersonaWriter{workingDir: workingDir, loader: loader}
}

// Create writes a new project-local persona. Fails if a project persona
// with the same name already exists. A library persona with the same name
// is allowed (the project file will override it).
func (w *ProjectPersonaWriter) Create(name string, body string) (*Persona, error) {
	if w.workingDir == "" {
		return nil, NewPersonaError(ErrorNoProjectContext, "a project working directory is required to create a persona", nil)
	}
	if err := validateName(name); err != nil {
		return nil, err
	}
	dir := w.loader.projectDir
	if err := os.MkdirAll(dir, 0o755); err != nil {
		return nil, NewPersonaError(ErrorFileOperation,
			fmt.Sprintf("failed to create project personas directory %s", dir), err)
	}
	filePath := filepath.Join(dir, name+PersonaFileExtension)
	if fileExists(filePath) {
		return nil, NewPersonaError(ErrorAlreadyExists,
			fmt.Sprintf("persona '%s' already exists at %s", name, filePath), nil)
	}
	normalized, err := normalizePersonaBody(name, body)
	if err != nil {
		return nil, err
	}
	if err := os.WriteFile(filePath, []byte(normalized), 0o644); err != nil {
		return nil, NewPersonaError(ErrorFileOperation,
			fmt.Sprintf("failed to write persona %s", filePath), err)
	}
	return readPersonaFile(filePath, SourceProject)
}

// Update overwrites an existing project-local persona. If the target
// persona exists only as a library persona, the update is rejected with
// ErrorReadOnlyLibrary.
func (w *ProjectPersonaWriter) Update(name string, body string) (*Persona, error) {
	if w.workingDir == "" {
		return nil, NewPersonaError(ErrorNoProjectContext, "a project working directory is required to update a persona", nil)
	}
	if err := validateName(name); err != nil {
		return nil, err
	}
	filePath := filepath.Join(w.loader.projectDir, name+PersonaFileExtension)
	if !fileExists(filePath) {
		// If a library persona exists, advise the user to fork first.
		libraryPath := filepath.Join(w.loader.personasDir, name+PersonaFileExtension)
		if fileExists(libraryPath) {
			return nil, NewPersonaError(ErrorReadOnlyLibrary,
				fmt.Sprintf("persona '%s' is a library persona and cannot be edited; fork it first", name), nil)
		}
		return nil, NewPersonaError(ErrorPersonaNotFound,
			fmt.Sprintf("project persona '%s' not found", name), nil)
	}
	normalized, err := normalizePersonaBody(name, body)
	if err != nil {
		return nil, err
	}
	if err := os.WriteFile(filePath, []byte(normalized), 0o644); err != nil {
		return nil, NewPersonaError(ErrorFileOperation,
			fmt.Sprintf("failed to write persona %s", filePath), err)
	}
	return readPersonaFile(filePath, SourceProject)
}

// Delete removes a project-local persona. Library personas are never
// deleted by this method.
func (w *ProjectPersonaWriter) Delete(name string) error {
	if w.workingDir == "" {
		return NewPersonaError(ErrorNoProjectContext, "a project working directory is required to delete a persona", nil)
	}
	if err := validateName(name); err != nil {
		return err
	}
	filePath := filepath.Join(w.loader.projectDir, name+PersonaFileExtension)
	if !fileExists(filePath) {
		libraryPath := filepath.Join(w.loader.personasDir, name+PersonaFileExtension)
		if fileExists(libraryPath) {
			return NewPersonaError(ErrorReadOnlyLibrary,
				fmt.Sprintf("persona '%s' is a library persona and cannot be deleted", name), nil)
		}
		return NewPersonaError(ErrorPersonaNotFound,
			fmt.Sprintf("project persona '%s' not found", name), nil)
	}
	if err := os.Remove(filePath); err != nil {
		return NewPersonaError(ErrorFileOperation,
			fmt.Sprintf("failed to delete persona %s", filePath), err)
	}
	return nil
}

// Fork copies a library persona into the project-local directory.
// `newName` may be empty to reuse the library name; if the target already
// exists, ErrorAlreadyExists is returned.
func (w *ProjectPersonaWriter) Fork(libraryName, newName string) (*Persona, error) {
	if w.workingDir == "" {
		return nil, NewPersonaError(ErrorNoProjectContext, "a project working directory is required to fork a persona", nil)
	}
	libraryPath := filepath.Join(w.loader.personasDir, libraryName+PersonaFileExtension)
	if !fileExists(libraryPath) {
		return nil, NewPersonaError(ErrorPersonaNotFound,
			fmt.Sprintf("library persona '%s' not found", libraryName), nil)
	}
	targetName := newName
	if targetName == "" {
		targetName = libraryName
	}
	if err := validateName(targetName); err != nil {
		return nil, err
	}
	content, err := os.ReadFile(libraryPath)
	if err != nil {
		return nil, NewPersonaError(ErrorFileOperation,
			fmt.Sprintf("failed to read library persona %s", libraryPath), err)
	}
	if targetName != libraryName {
		// Rewrite the frontmatter name so the forked file matches its new
		// filename and is discoverable under the new name.
		content = []byte(rewriteFrontmatterName(string(content), targetName))
	}
	if err := os.MkdirAll(w.loader.projectDir, 0o755); err != nil {
		return nil, NewPersonaError(ErrorFileOperation,
			fmt.Sprintf("failed to create project personas directory %s", w.loader.projectDir), err)
	}
	targetPath := filepath.Join(w.loader.projectDir, targetName+PersonaFileExtension)
	if fileExists(targetPath) {
		return nil, NewPersonaError(ErrorAlreadyExists,
			fmt.Sprintf("persona '%s' already exists at %s", targetName, targetPath), nil)
	}
	if err := os.WriteFile(targetPath, content, 0o644); err != nil {
		return nil, NewPersonaError(ErrorFileOperation,
			fmt.Sprintf("failed to write forked persona %s", targetPath), err)
	}
	return readPersonaFile(targetPath, SourceProject)
}

// ProjectDir returns the absolute path to the project-local persona dir.
func (w *ProjectPersonaWriter) ProjectDir() string { return w.loader.projectDir }

// validateName keeps names safe for filesystem use.
func validateName(name string) error {
	trimmed := strings.TrimSpace(name)
	if trimmed == "" {
		return NewPersonaError(ErrorValidation, "persona name cannot be empty", nil)
	}
	if strings.ContainsAny(trimmed, "/\\") || strings.HasPrefix(trimmed, ".") {
		return NewPersonaError(ErrorValidation,
			fmt.Sprintf("invalid persona name %q", name), nil)
	}
	return nil
}

// normalizePersonaBody ensures the persona body has valid frontmatter and a
// name matching the file name. If the caller supplies a full markdown
// document with frontmatter, the frontmatter's name is forced to `name`.
// If the caller supplies raw body text without frontmatter, a minimal
// frontmatter block is synthesized.
func normalizePersonaBody(name string, body string) (string, error) {
	body = strings.TrimLeft(body, "\n")
	if body == "" {
		return "", NewPersonaError(ErrorValidation, "persona body cannot be empty", nil)
	}
	if !strings.HasPrefix(body, "---") {
		body = fmt.Sprintf("---\nname: %s\nroles: [general]\ndescription: %s\ntags: []\n---\n\n%s", name, name, body)
	}
	// Validate by parsing.
	parsed, err := parsePersona([]byte(body))
	if err != nil {
		return "", err
	}
	if parsed.Name != name {
		body = rewriteFrontmatterName(body, name)
	}
	return body, nil
}

// rewriteFrontmatterName rewrites the `name:` key in a persona document's
// YAML frontmatter. If no frontmatter is present, the content is returned
// unchanged.
func rewriteFrontmatterName(content string, newName string) string {
	lines := strings.Split(content, "\n")
	if len(lines) == 0 || lines[0] != "---" {
		return content
	}
	end := -1
	for i := 1; i < len(lines); i++ {
		if lines[i] == "---" {
			end = i
			break
		}
	}
	if end == -1 {
		return content
	}
	frontmatter := strings.Join(lines[1:end], "\n")
	var node yaml.Node
	if err := yaml.Unmarshal([]byte(frontmatter), &node); err != nil {
		return content
	}
	// node.Content[0] is the document's mapping node.
	if len(node.Content) == 0 {
		return content
	}
	mapping := node.Content[0]
	if mapping.Kind != yaml.MappingNode {
		return content
	}
	foundName := false
	for i := 0; i < len(mapping.Content); i += 2 {
		if mapping.Content[i].Value == "name" {
			mapping.Content[i+1].Value = newName
			foundName = true
			break
		}
	}
	if !foundName {
		mapping.Content = append([]*yaml.Node{
			{Kind: yaml.ScalarNode, Value: "name"},
			{Kind: yaml.ScalarNode, Value: newName},
		}, mapping.Content...)
	}
	rewritten, err := yaml.Marshal(&node)
	if err != nil {
		return content
	}
	newFrontmatter := strings.TrimRight(string(rewritten), "\n")
	var b strings.Builder
	b.WriteString("---\n")
	b.WriteString(newFrontmatter)
	b.WriteString("\n---\n")
	if end+1 < len(lines) {
		b.WriteString(strings.Join(lines[end+1:], "\n"))
	}
	return b.String()
}

# DDx GraphQL Schema
# Single source of truth for the SvelteKit UI.
# Every type field is doc-commented. Relay cursor connections on all lists.

# ============================================
# Scalars
# ============================================

"""ISO-8601 datetime string"""
scalar DateTime

"""Arbitrary JSON blob (used for opaque map fields)"""
scalar JSON

# ============================================
# Interfaces
# ============================================

"""Node is the Relay global object identification interface"""
interface Node {
  """Globally unique identifier"""
  id: ID!
}

# ============================================
# Pagination (Relay Cursor Connections)
# ============================================

"""PageInfo carries cursor-based pagination state (Relay spec)"""
type PageInfo {
  """True when more edges exist after the last returned edge"""
  hasNextPage: Boolean!
  """True when more edges exist before the first returned edge"""
  hasPreviousPage: Boolean!
  """Cursor of the first edge in the current page (null when empty)"""
  startCursor: String
  """Cursor of the last edge in the current page (null when empty)"""
  endCursor: String
}

# ============================================
# Node & Project
# ============================================

"""NodeInfo represents the running ddx-server instance"""
type NodeInfo implements Node {
  """Unique node identifier (stable across restarts)"""
  id: ID!
  """Human-readable node name"""
  name: String!
  """Timestamp when the server process started"""
  startedAt: DateTime!
  """Timestamp of the most recent heartbeat"""
  lastSeen: DateTime!
}

"""Project represents a registered ddx project on this node"""
type Project implements Node {
  """Unique project identifier"""
  id: ID!
  """Short display name"""
  name: String!
  """Absolute filesystem path to the project root"""
  path: String!
  """Git remote URL, if configured"""
  gitRemote: String
  """When the project was first registered with the server"""
  registeredAt: DateTime!
  """Timestamp of the last successful probe"""
  lastSeen: DateTime!
  """True when the project path is inaccessible"""
  unreachable: Boolean
  """Set when the project has been tombstoned (soft-deleted)"""
  tombstonedAt: DateTime
}

"""ProjectEdge is one edge in a ProjectConnection"""
type ProjectEdge {
  """The project at this position"""
  node: Project!
  """Opaque cursor for pagination"""
  cursor: String!
}

"""ProjectConnection is a Relay cursor connection of projects"""
type ProjectConnection {
  """Ordered list of project edges"""
  edges: [ProjectEdge!]!
  """Pagination metadata"""
  pageInfo: PageInfo!
  """Total number of projects matching the filter"""
  totalCount: Int!
}

# ============================================
# Beads
# ============================================

"""Bead is a portable work item with lifecycle metadata"""
type Bead implements Node {
  """Unique bead identifier (e.g. "ddx-a1b2c3d4")"""
  id: ID!
  """Short summary of the work"""
  title: String!
  """Lifecycle status: open, in-progress, closed, blocked"""
  status: String!
  """Numeric priority (lower is higher priority)"""
  priority: Int!
  """Issue classification (e.g. "task", "bug", "spike")"""
  issueType: String!
  """Agent or human currently responsible"""
  owner: String
  """When the bead was created"""
  createdAt: DateTime!
  """Who or what created the bead"""
  createdBy: String
  """Last modification timestamp"""
  updatedAt: DateTime!
  """Freeform labels for filtering and grouping"""
  labels: [String!]
  """Project identifier this bead belongs to"""
  projectID: String
  """Parent bead ID for hierarchy"""
  parent: String
  """Full description / body text"""
  description: String
  """Acceptance criteria text"""
  acceptance: String
  """Freeform notes appended during work"""
  notes: String
  """Dependency edges to other beads"""
  dependencies: [Dependency!]
}

"""Dependency is a directed edge between two beads"""
type Dependency {
  """The bead that has the dependency"""
  issueId: String!
  """The bead that must be completed first"""
  dependsOnId: String!
  """Dependency kind (e.g. "blocks", "relates-to")"""
  type: String!
  """When the dependency was created"""
  createdAt: String
  """Who created the dependency"""
  createdBy: String
  """Opaque metadata attached to the link"""
  metadata: String
}

"""BeadEdge is one edge in a BeadConnection"""
type BeadEdge {
  """The bead at this position"""
  node: Bead!
  """Opaque cursor for pagination"""
  cursor: String!
}

"""BeadConnection is a Relay cursor connection of beads"""
type BeadConnection {
  """Ordered list of bead edges"""
  edges: [BeadEdge!]!
  """Pagination metadata"""
  pageInfo: PageInfo!
  """Total number of beads matching the filter"""
  totalCount: Int!
}

"""BeadStatusCounts holds aggregate bead counts by status"""
type BeadStatusCounts {
  """Number of beads in open status"""
  open: Int!
  """Number of beads in closed status"""
  closed: Int!
  """Number of beads with unclosed dependencies"""
  blocked: Int!
  """Number of open beads whose dependencies are all closed"""
  ready: Int!
  """Total number of beads"""
  total: Int!
}

# ============================================
# Documents (library)
# ============================================

"""Document represents a docgraph document with dependency tracking"""
type Document implements Node {
  """Document identifier (usually the relative path)"""
  id: ID!
  """Filesystem path relative to the library root"""
  path: String!
  """Human-readable title extracted from frontmatter"""
  title: String!
  """IDs of documents this document depends on"""
  dependsOn: [String!]!
  """IDs of input artifacts consumed by this document"""
  inputs: [String!]!
  """IDs of documents that depend on this document"""
  dependents: [String!]!
  """Review state metadata (null if never reviewed)"""
  review: DocumentReview
  """True if parked (excluded from staleness checks)"""
  parkingLot: Boolean!
  """Prompt text embedded in the document frontmatter"""
  prompt: String
  """Execution definition embedded in the document (null if none)"""
  execDef: DocumentExecDef
  """Raw file content (populated only by documentByPath, null in list queries)"""
  content: String
}

"""DocumentReview holds review-state metadata for a document"""
type DocumentReview {
  """Hash of the document content at review time"""
  selfHash: String!
  """Map of dependency IDs to their hashes at review time"""
  deps: JSON!
  """ISO-8601 timestamp of the last review"""
  reviewedAt: String!
}

"""DocumentExecDef holds an execution definition embedded in a document"""
type DocumentExecDef {
  """Definition identifier"""
  id: String
  """IDs of artifacts this definition produces or consumes"""
  artifactIds: [String!]
  """How to invoke the execution"""
  executor: ExecutorSpec
  """How to interpret the result"""
  result: ResultSpec
  """Evaluation criteria and thresholds"""
  evaluation: Evaluation
  """Whether the definition is currently active"""
  active: Boolean
  """Whether the definition must pass for merge"""
  required: Boolean
  """Whether this definition was discovered from the docgraph"""
  graphSource: Boolean
  """When the definition was created"""
  createdAt: DateTime
}

"""ExecutorSpec describes how to invoke an execution"""
type ExecutorSpec {
  """Execution kind (e.g. "shell", "agent")"""
  kind: String!
  """Command and arguments to run"""
  command: [String!]
  """Working directory for the command"""
  cwd: String
  """Environment variables as key-value pairs"""
  env: JSON
  """Maximum execution time in milliseconds"""
  timeoutMs: Int
}

"""ResultSpec describes how to interpret an execution result"""
type ResultSpec {
