// personaNew creates a new project-local persona. If bodyFile is empty, a
// scaffold is generated from the default template.
func personaNew(workingDir, name, bodyFile string) (*persona.Persona, error) {
	if workingDir == "" {
		return nil, fmt.Errorf("working directory must be provided")
	}
	body, err := readBodyInput(bodyFile, name)
	if err != nil {
		return nil, err
	}
	writer := persona.NewProjectPersonaWriter(workingDir)
	return writer.Create(name, body)
}

// personaEdit updates a project-local persona. If bodyFile is empty, it
// opens $EDITOR on the file.
func personaEdit(cmd *cobra.Command, workingDir, name, bodyFile string) (*persona.Persona, error) {
	if workingDir == "" {
		return nil, fmt.Errorf("working directory must be provided")
	}
	writer := persona.NewProjectPersonaWriter(workingDir)

	if bodyFile != "" {
		body, err := os.ReadFile(bodyFile)
		if err != nil {
			return nil, fmt.Errorf("failed to read body file %s: %w", bodyFile, err)
		}
		return writer.Update(name, string(body))
	}

	// Interactive edit: open $EDITOR on the project file in place, then
	// re-read to validate.
	projectFile := filepath.Join(writer.ProjectDir(), name+".md")
	if _, err := os.Stat(projectFile); os.IsNotExist(err) {
		// Surface the same error the writer would.
		if _, err := writer.Update(name, ""); err != nil {
			return nil, err
		}
	}

	editor := os.Getenv("EDITOR")
	if editor == "" {
		editor = "vi"
	}
	editCmd := exec.Command(editor, projectFile) // #nosec G204 — intentional $EDITOR invocation
	editCmd.Stdin = cmd.InOrStdin()
	editCmd.Stdout = cmd.OutOrStdout()
	editCmd.Stderr = cmd.ErrOrStderr()
	if err := editCmd.Run(); err != nil {
		return nil, fmt.Errorf("editor exited with error: %w", err)
	}
	data, err := os.ReadFile(projectFile)
	if err != nil {
		return nil, fmt.Errorf("failed to re-read persona after edit: %w", err)
	}
	return writer.Update(name, string(data))
}

// personaFork copies a library persona into the project-local dir.
func personaFork(workingDir, libraryName, newName string) (*persona.Persona, error) {
	if workingDir == "" {
		return nil, fmt.Errorf("working directory must be provided")
	}
	writer := persona.NewProjectPersonaWriter(workingDir)
	return writer.Fork(libraryName, newName)
}

// personaDelete removes a project-local persona.
func personaDelete(workingDir, name string) error {
	if workingDir == "" {
		return fmt.Errorf("working directory must be provided")
	}
	writer := persona.NewProjectPersonaWriter(workingDir)
	return writer.Delete(name)
}

// readBodyInput resolves the body for `ddx persona new`. If the caller
// supplies a path, read it; otherwise fall back to the scaffold template.
func readBodyInput(bodyFile, name string) (string, error) {
	if bodyFile == "" {
		return scaffoldPersonaBody(name), nil
	}
	data, err := os.ReadFile(bodyFile)
	if err != nil {
		return "", fmt.Errorf("failed to read body file %s: %w", bodyFile, err)
	}
	return string(data), nil
}

// scaffoldPersonaBody returns a minimal but valid persona markdown body.
func scaffoldPersonaBody(name string) string {
	return fmt.Sprintf(`---
name: %s
roles: [general]
description: Project persona %s
tags: []
---

# %s

TODO: describe what this persona does for your team.
`, name, name, name)
}

// IsLibraryReadOnly returns true if err represents a read-only library
// persona rejection from the persona package.
func IsLibraryReadOnly(err error) bool {
	var pe *persona.PersonaError
	if errors.As(err, &pe) {
		return pe.Type == persona.ErrorReadOnlyLibrary
	}
	return false
}

package graphql

import (
	"context"
	"fmt"

	"github.com/DocumentDrivenDX/ddx/internal/persona"
)

// Personas is the resolver for the personas field.
func (r *queryResolver) Personas(ctx context.Context, projectID *string) ([]*Persona, error) {
	loader := persona.NewPersonaLoader(r.personaProjectRoot(projectID))
	ps, err := loader.ListPersonas()
	if err != nil {
		return nil, fmt.Errorf("loading personas: %w", err)
	}
	gql := make([]*Persona, len(ps))
	for i, p := range ps {
		gql[i] = personaToGQL(p)
	}
	return gql, nil
}

// Persona is the resolver for the persona field.
func (r *queryResolver) Persona(ctx context.Context, name string, projectID *string) (*Persona, error) {
	loader := persona.NewPersonaLoader(r.personaProjectRoot(projectID))
	p, err := loader.LoadPersona(name)
	if err != nil {
		return nil, nil //nolint:nilerr // not-found is represented as null
	}
	return personaToGQL(p), nil
}

// personaProjectRoot resolves the working directory for persona loading.
// When a project ID is provided, it resolves via projectRoot; otherwise
// falls back to the server's working directory.
func (r *queryResolver) personaProjectRoot(projectID *string) string {
	if projectID != nil && *projectID != "" {
		return r.projectRoot(*projectID)
	}
	return r.WorkingDir
}

// PersonaByRole is the resolver for the personaByRole field.
func (r *queryResolver) PersonaByRole(ctx context.Context, role string) (*Persona, error) {
	loader := persona.NewPersonaLoader(r.WorkingDir)
	ps, err := loader.FindByRole(role)
	if err != nil || len(ps) == 0 {
		return nil, nil
	}
	return personaToGQL(ps[0]), nil
}

// Coordinators is the resolver for the coordinators field.
func (r *queryResolver) Coordinators(ctx context.Context) ([]*CoordinatorMetricsEntry, error) {
	return r.State.GetCoordinatorsGraphQL(), nil
}

// CoordinatorMetricsByProject is the resolver for the coordinatorMetricsByProject field.
func (r *queryResolver) CoordinatorMetricsByProject(ctx context.Context, projectRoot string) (*CoordinatorMetrics, error) {
	return r.State.GetCoordinatorMetricsByProjectGraphQL(projectRoot), nil
}

// ─── helpers ──────────────────────────────────────────────────────────────────

func personaToGQL(p *persona.Persona) *Persona {
	source := p.Source
	if source == "" {
		source = persona.SourceLibrary
	}
	var filePath *string
	if p.FilePath != "" {
		fp := p.FilePath
		filePath = &fp
	}
	return &Persona{
		ID:          "persona-" + p.Name,
		Name:        p.Name,
		Roles:       p.Roles,
		Description: p.Description,
		Tags:        p.Tags,
		Content:     p.Content,
		Body:        p.Content,
		Source:      source,
		Bindings:    []*PersonaBinding{},
		FilePath:    filePath,
	}
}

func personaConnectionFrom(personas []*Persona, first *int, after *string, last *int, before *string) *PersonaConnection {
	all := make([]*PersonaEdge, len(personas))
	ids := make([]string, len(personas))
	for i, p := range personas {
		all[i] = &PersonaEdge{Node: p, Cursor: encodeStableCursor(p.ID)}
		ids[i] = p.ID
	}
	startIdx, endIdx := stablePageBounds(ids, after, before)
	slice := all[startIdx:endIdx]
	truncByFirst, truncByLast := false, false
	if first != nil && *first >= 0 && *first < len(slice) {
		slice = slice[:*first]
		truncByFirst = true
	}
	if last != nil && *last >= 0 && *last < len(slice) {
		slice = slice[len(slice)-*last:]
		truncByLast = true
	}
	pageInfo := &PageInfo{
		HasPreviousPage: startIdx > 0 || truncByLast,
		HasNextPage:     endIdx < len(all) || truncByFirst,
	}
	if len(slice) > 0 {
		pageInfo.StartCursor = &slice[0].Cursor
		pageInfo.EndCursor = &slice[len(slice)-1].Cursor
	}
	return &PersonaConnection{Edges: slice, PageInfo: pageInfo, TotalCount: len(all)}
}
